from agent import *from models.products import *import simplejsonXCAT = ['All Products', 'About']def run(context, session):    session.queue(Request('https://purosound.com/', use='curl', force_charset='utf-8'), process_frontpage, {})def process_frontpage(data, context, session):    cats = data.xpath('//ul[contains(@class, "site-nav site-navigation")]/li')    for cat in cats:        url = cat.xpath('a/@href').string()        name = cat.xpath('a//text()').string()        if name not in XCAT:            subcats = cat.xpath('ul/li/a')            if subcats:                for subcat in subcats:                    url = subcat.xpath('@href').string()                    subcat_name = subcat.xpath('text()').string()                    session.queue(Request(url), process_prodlist, dict(cat=name + '|' + subcat_name))            else:                session.queue(Request(url), process_prodlist, dict(cat=name))def process_prodlist(data, context, session):    prods = data.xpath('//div[@class="grid-product__content"]')    for prod in prods:        link = prod.xpath('a[@class="grid-product__link"]/@href').string().split('/')[-1]        url = 'https://purosound.com/products/' + link        name = prod.xpath('.//div[@class="grid-product__title"]//text()').string()        session.queue(Request(url, use='curl', force_charset='utf-8'), process_product, dict(context, url=url, name=name))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url, use='curl', force_charset='utf-8'), process_prodlist, dict(context))def process_product(data, context, session):    product = Product()    product.name = context['name']    product.category = context['cat']    product.url = context['url']    product.ssid = data.xpath('//span[@class="klaviyo-star-rating-widget"]/@data-id').string()    try:        prod_json = simplejson.loads(data.xpath('''//script[contains(text(), '"@type": "Product"')]//text()''').string())        product.sku = prod_json.get('sku')        product.manufacturer = prod_json.get('brand', {}).get('name')        prod_json2 = simplejson.loads(data.xpath('//textarea[@aria-label="Product JSON"]//text()').string())        ean = prod_json2[0].get('barcode')        if ean:            product.add_property(type='id.ean', value=ean)    except:        pass    token = data.xpath('''//script[contains(., 'klaviyo.init({')]//text()''').string()    if token:        token = token.split('account: "')[-1].split('"')[0]        revs_url = "https://fast.a.klaviyo.com/reviews/api/client_reviews/{pid}/?product_id={pid}&company_id={token}&limit=5&offset=0&sort=0&filter=&type=reviews&media=false".format(pid=product.ssid, token=token)        session.do(Request(revs_url, use='curl', force_charset='utf-8', max_age=0), process_reviews, dict(product=product, token=token))def process_reviews(data, context, session):    product = context['product']    revs_json = simplejson.loads(data.content)    revs = revs_json.get('reviews', [])    for rev in revs:        pid = rev.get('product', {}).get('shopify_id')        if pid and str(pid) != product.ssid:            continue        review = Review()        review.type = 'user'        review.url = product.url        review.title = rev.get('title')        review.ssid = str(rev['id'])        date = rev.get('created_at')        if date:            review.date = date.split('T')[0]        author = rev.get('author')        if author:            review.authors.append(Person(name=author, ssid=author))        is_verified = rev.get('verified')        if is_verified:            review.add_property(type='is_verified_buyer', value=True)        grade_overall = rev.get('rating')        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        excerpt = rev.get('content')        if excerpt:            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)    revs_cnt = context.get('revs_cnt', revs_json.get('product', {}).get('review_count'))    offset = context.get('offset', 0) + 5    if revs_cnt and int(revs_cnt) > offset:        next_url = "https://fast.a.klaviyo.com/reviews/api/client_reviews/{pid}/?product_id={pid}&company_id={token}&limit=5&offset={offset}&sort=0&filter=&type=reviews&media=false".format(pid=product.ssid, offset=offset, token=context['token'])        session.do(Request(next_url), process_reviews, dict(product=product, revs_cnt=revs_cnt, offset=offset, token=context['token']))    elif product.reviews:        session.emit(product)